const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;
const COMPONENT_UNIT_PRICE = 25;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const roundPremium = (amount: number): number => Math.ceil(amount);

const priceForComponentCount = (count: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const leftovers = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_PRICE + leftovers * COMPONENT_UNIT_PRICE;
};

const countComponentsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const baseForItems = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const nonComponents = items.filter((item) => !isComponent(item));
  const nonComponentBase = nonComponents.reduce((sum, item) => sum + basePremiumFor(item), 0);
  const componentCountsByType = countComponentsByType(components);
  let componentBase = 0;
  for (const count of componentCountsByType.values()) {
    componentBase += priceForComponentCount(count);
  }
  return nonComponentBase + componentBase;
};

